// ── Interactive lesson system (Duolingo-style) ──

// hotspots turn a "read this" teach card into an active one: the learner taps each
// labelled part of the circuit to reveal what it does, and can only continue once
// every part has been explored. Reading becomes light doing.
export type LessonStepTeach = { type: 'teach'; title: string; body: string; diagram?: string; circuitDiagram?: string; showCurrentFlow?: boolean; hotspots?: Array<{ region: string; label: string; detail: string }> };
// optionImages (when present, one per option) renders the choices as a picture grid
// ("tap the resistor") instead of a text list. Falls back to the text option if an
// image is missing or fails to load, so a question is never broken by absent art.
export type LessonStepMC = { type: 'multiple_choice'; question: string; options: string[]; optionImages?: string[]; correct: number; explanation: string; circuitDiagram?: string };
export type LessonStepTF = { type: 'true_false'; statement: string; correct: boolean; explanation: string; circuitDiagram?: string };
// tiles (when present) turns the blank into a word/number/unit bank: the learner
// assembles the answer by tapping tiles (Duolingo's word-bank), instead of typing.
// The answer is built by joining the tapped tiles with spaces. Falls back to a text
// input when tiles is absent.
export type LessonStepFill = { type: 'fill_blank'; prompt: string; blank: string; answer: string; hint: string; circuitDiagram?: string; tiles?: string[] };
// images (when present, one per pair) shows a picture for each left item, so match
// becomes symbol/photo -> name. Falls back to the text left label when an image is absent.
export type LessonStepMatch = { type: 'match'; instruction: string; pairs: Array<[string, string]>; images?: string[] };
export type LessonStepSpotError = { type: 'spot_error'; question: string; circuitDiagram: string; correctRegion: string; explanation: string };
export type LessonStepIdentify = { type: 'identify_component'; question: string; circuitDiagram: string; correctComponent: string; explanation: string };
export type LessonStepDraw = { type: 'draw_connection'; instruction: string; terminals: Array<{ x: number; y: number; label: string; id: string }>; expectedConnections: Array<[string, string]>; explanation: string };
export type LessonStepDragOrder = { type: 'drag_order'; instruction: string; items: string[]; correctOrder: number[] };
// Prediction family: the learner commits to a prediction, then the circuit reveals the truth.
// This is the highest-value pattern for killing misconceptions (predict → commit → reveal).
// meter (when present) replaces the option list with a needle gauge + slider: the
// learner dials in the reading and is correct within tolerance of the target. A real
// "set the value" interaction instead of picking a number from a list.
export type LessonStepPredictReading = { type: 'predict_reading'; question: string; circuitDiagram?: string; options: string[]; optionImages?: string[]; correct: number; explanation: string; meter?: { unit: string; min: number; max: number; step?: number; target: number; tolerance: number } };
export type LessonStepPredictBehavior = { type: 'predict_behavior'; question: string; circuitDiagram?: string; options: string[]; optionImages?: string[]; correct: number; explanation: string };
// bands (when present) replaces the option list with an interactive 4-band resistor:
// the learner sets the colour bands to encode targetOhms. The signature electronics
// skill, made tactile.
export type LessonStepChooseResistor = { type: 'choose_resistor'; question: string; circuitDiagram?: string; options: string[]; optionImages?: string[]; correct: number; explanation: string; bands?: { targetOhms: number } };
// Construction / repair / tracing family: the learner manipulates a circuit
// directly rather than picking from a text list. These kill the misconceptions a
// multiple-choice question cannot reach.
//   trace_current   — tap the parts the current flows through, in loop order
//                     (kills "current gets used up"; proves the complete loop).
//   fix_the_circuit — tap the faulty part, THEN choose the correct repair
//                     (diagnosis + remedy, a step beyond spot_error's diagnosis).
//   build_to_spec   — assemble a circuit by placing the right parts from a palette
//                     (with distractor parts) into ordered slots (synthesis).
export type LessonStepTraceCurrent = { type: 'trace_current'; question: string; circuitDiagram: string; correctPath: string[]; explanation: string };
export type LessonStepFixCircuit = { type: 'fix_the_circuit'; question: string; circuitDiagram: string; faultRegion: string; fixes: string[]; correctFix: number; explanation: string };
export type LessonStepBuildToSpec = { type: 'build_to_spec'; instruction: string; palette: string[]; slots: number; correct: number[]; explanation: string; circuitDiagram?: string };
// draw_circuit — the embodied hero: the learner DRAWS the circuit on a canvas and
// Gemini Vision grades it (the orphaned hackathon capability, now in the lessons).
// `expected` lists the component keywords the model should find in the drawing.
export type LessonStepDrawCircuit = { type: 'draw_circuit'; instruction: string; expected: string[]; hint: string; explanation: string };
// draw_fix — draw the missing/correct component directly ON TOP of a shown circuit.
// The circuit image and the learner's drawing are composited into one picture and
// graded by Gemini Vision. The diagnose-and-repair task, embodied: instead of being
// told where to click, the learner adds the fix themselves.
export type LessonStepDrawFix = { type: 'draw_fix'; instruction: string; circuitDiagram: string; expected: string[]; hint: string; explanation: string };
export type LessonStep = LessonStepTeach | LessonStepMC | LessonStepTF | LessonStepFill | LessonStepMatch | LessonStepSpotError | LessonStepIdentify | LessonStepDraw | LessonStepDragOrder | LessonStepPredictReading | LessonStepPredictBehavior | LessonStepChooseResistor | LessonStepTraceCurrent | LessonStepFixCircuit | LessonStepBuildToSpec | LessonStepDrawCircuit | LessonStepDrawFix;

// Difficulty tier for a question (used by leveling: Bronze favours tier 1, Silver
// tier 2, Gold tier 3). Untagged steps default to tier 1. A lesson with a deep,
// tiered pool of questions lets Bronze/Silver/Gold draw DIFFERENT, harder slices
// instead of reshuffling the same handful.
export type Difficulty = 1 | 2 | 3;
export type AuthoredStep = LessonStep & { difficulty?: Difficulty };

