  'Jumper Wires': {
    xpReward: 20,
    steps: [
      { type: 'teach', title: 'Bridging the Board', body: 'Jumper wires carry a connection from one point on the board to another, for example from the + rail to a component row. Solid-core wire (around 22 gauge) is ideal: it pushes cleanly into the holes and holds its shape. Stranded wire frays and is hard to insert.' },
      { type: 'multiple_choice', question: 'Which wire is best for a breadboard?', options: ['Thick stranded wire', 'Solid-core wire (~22 gauge)', 'Bare wire with no insulation', 'Any household cable'], correct: 1, explanation: 'Solid-core wire inserts cleanly and stays put; stranded wire frays in the holes.' },
      { type: 'teach', title: 'Keep It Tidy', body: 'Short, flat jumpers that hug the board are easier to follow and debug than long arcs flying across it. A tidy layout is not just pretty, it is how you spot a wrong connection at a glance.' },
      { type: 'true_false', statement: 'Long, messy jumper wires make a circuit easier to debug.', correct: false, explanation: 'The opposite. Tidy, short jumpers let you trace the circuit and catch mistakes quickly.' },
      { type: 'multiple_choice', question: 'A jumper wire from the + rail to row 10 does what?', options: ['Nothing at all, jumpers are just decorative', 'Brings the positive supply to row 10', 'Creates a dangerous short across the board', 'Removes any power that row 10 already had'], correct: 1, explanation: 'The jumper carries + from the rail to that row, so components in row 10 can use it.' },
      { type: 'multiple_choice', question: 'Why is solid-core wire preferred over stranded for a breadboard?', options: ['It is a much better electrical conductor overall', 'It pushes cleanly into holes and holds its shape', 'It is the only wire type that carries current', 'Stranded wire is actually illegal to use indoors'], correct: 1, explanation: 'Solid-core inserts neatly and stays put; stranded frays in the holes.' },
      { type: 'true_false', statement: 'Short, flat jumpers that hug the board are easier to trace and debug.', correct: true, explanation: 'A tidy layout lets you follow the circuit and spot a wrong connection at a glance.' },
      { type: 'drag_order', instruction: 'Order the steps to power a component row from the rail.', items: ['Connect the supply to the + and − rails', 'Run a jumper from the + rail to the component row', 'Place the component in that row', 'Run a jumper from the component to the − rail'], correctOrder: [0, 1, 2, 3] },
      { type: 'multiple_choice', question: 'Tap the jumper wires.', options: ['Jumper wires', 'Resistor', 'LED', 'Potentiometer'], optionImages: ['/components/jumper-wires.png', '/components/resistor.png', '/components/led.png', '/components/potentiometer.png'], correct: 0, explanation: 'Jumper wires are the short insulated leads with pin ends that bridge points on the board.' },
      { type: 'match', instruction: 'Match each wire choice to why it matters.', pairs: [['Solid-core wire', 'Inserts cleanly, holds shape'], ['Stranded wire', 'Frays in the holes'], ['Short jumper', 'Easy to trace and debug'], ['Long messy jumper', 'Hard to follow']] },
      { type: 'fill_blank', prompt: 'For breadboards, ___-core wire (about 22 gauge) is the right choice.', blank: '___', answer: 'solid', tiles: ['solid', 'stranded', 'bare', 'braided'], hint: 'The opposite of the kind that frays.' },
      { type: 'true_false', statement: 'Stranded wire pushes into breadboard holes more reliably than solid-core.', correct: false, explanation: 'No. Stranded frays and is hard to insert; solid-core is the reliable choice.' },
      { type: 'draw_circuit', instruction: 'Draw a circuit and show the jumper wires that bridge the parts into a loop.', expected: ['battery', 'resistor', 'led'], hint: 'Draw the battery, resistor and LED, then draw the connecting wires (jumpers) that join them into one closed loop.', explanation: 'Jumpers are just the wires that carry a connection from one point to another, closing the loop between your parts.' },
      { type: 'true_false', statement: 'A jumper wire creates a new electrical connection between the two points it links.', correct: true, explanation: 'That is its whole job: to carry a connection from one hole to another.' },
      { type: 'fill_blank', prompt: 'A wire that bridges two points on the board is called a ___ wire.', blank: '___', answer: 'jumper', tiles: ['jumper', 'power', 'ground', 'signal'], hint: 'It jumps a connection across the board.' },
      { type: 'drag_order', instruction: 'Order these jumpers by how easy the build is to trace, easiest first.', items: ['Short flat jumper hugging the board', 'A medium jumper with one bend', 'A long arc across the board', 'A tangle of long crossing wires'], correctOrder: [0, 1, 2, 3] },
      { type: 'true_false', statement: 'Colour-coding jumpers (red for +, black for −) makes a build easier to read.', correct: true, explanation: 'Consistent colours let you trace power and ground at a glance, even though electrically any colour works.' },
    ],
  },

