  'Linear Regulator Heat': {
    xpReward: 35,
    steps: [
      { type: 'teach', title: 'The Voltage It Drops Becomes Heat', body: 'A linear regulator throws away the difference between input and output as heat. The power it dissipates is:\n\nP = (Vin − Vout) × Iout\n\nThe bigger the voltage drop or the load current, the more heat. That heat is the linear regulator\'s main weakness, and why a big drop at high current needs a heatsink, or a switching regulator instead.' },

      { type: 'fill_blank', difficulty: 1, prompt: 'A linear regulator\'s heat is P = (Vin − Vout) × ___.', blank: '___', answer: 'Iout', hint: 'The load current flowing through it.' },
      { type: 'multiple_choice', difficulty: 1, question: 'A linear regulator gets rid of the excess voltage as...', options: ['Heat', 'Light', 'Sound', 'Stored charge'], correct: 0, explanation: 'The dropped voltage times the current is dissipated as heat.' },
      { type: 'true_false', difficulty: 1, statement: 'A larger input-to-output voltage gap makes a linear regulator run hotter.', correct: true, explanation: 'P = (Vin − Vout) × Iout, so a bigger drop means more heat at a given current.' },

      { type: 'predict_reading', difficulty: 2, question: 'A 7805 drops 12V to 5V at 0.5A. Dial the power it dissipates (P = (Vin−Vout)×I).', options: ['3.5 W'], correct: 0, meter: { unit: 'W', min: 0, max: 8, step: 0.1, target: 3.5, tolerance: 0.4 }, explanation: 'P = (12 − 5) × 0.5 = 3.5 W, a lot of heat for a small chip.' },
      { type: 'fill_blank', difficulty: 1, prompt: 'Build the linear-regulator heat formula.', blank: '___', answer: 'P = ( Vin − Vout ) × Iout', tiles: ['P', '=', '(', 'Vin', '−', 'Vout', ')', '×', 'Iout', '/', '+'], hint: 'The voltage it drops, times the current through it.' },
      { type: 'true_false', difficulty: 2, statement: 'A regulator dropping 3.5W and running hot is helped by a heatsink or a lower input voltage.', correct: true, explanation: 'Less voltage drop (lower Vin) or better heat-sinking reduces the temperature.' },

      { type: 'multiple_choice', difficulty: 3, question: 'A linear regulator\'s efficiency is roughly Vout/Vin. Stepping 12V to 5V, the efficiency is about...', options: ['≈ 42%', '≈ 90%', '≈ 70%', '≈ 100%'], correct: 0, explanation: '5/12 ≈ 0.42, so ~42%. The other ~58% of the power becomes heat.' },
      { type: 'predict_reading', difficulty: 3, question: 'You step 12V to 5V at 1A with a linear regulator. Dial the wasted heat.', options: ['7 W'], correct: 0, meter: { unit: 'W', min: 0, max: 15, step: 0.5, target: 7, tolerance: 0.7 }, explanation: 'P = (12 − 5) × 1 = 7 W wasted as heat: exactly where a switching regulator wins.' },
      { type: 'match', difficulty: 1, instruction: 'Match each real part to its role in a linear-regulator supply.', pairs: [['IC chip', 'The regulator'], ['Electrolytic capacitor', 'Input/output bulk smoothing'], ['Resistor', 'Sets a bias or load'], ['Diode', 'Input protection']], images: ['/components/ic-dip.png', '/components/capacitor-electrolytic.png', '/components/resistor.png', '/components/diode.png'] },
      { type: 'true_false', difficulty: 1, statement: 'A linear regulator throws away the dropped voltage as heat.', correct: true, explanation: 'P = (Vin − Vout) × Iout is dissipated as heat, the linear regulator\'s main weakness.' },
    ],
  },

  'Switching Regulators': {
    xpReward: 35,
    steps: [
      { type: 'teach', title: 'Switch Fast, Waste Little', body: 'A switching regulator does not burn off the excess as heat. Instead it rapidly switches the input on and off into an inductor and capacitor, storing and releasing energy to build the desired output. Because the switch is either fully on (low loss) or fully off (no current), very little power is wasted. Efficiencies of 85 to 95% are common.' },
      { type: 'teach', title: 'Buck, Boost, and the Catch', body: 'A buck converter steps the voltage DOWN; a boost converter steps it UP (something a linear regulator can never do); a buck-boost can do either. The price is more complexity and switching noise on the output, so switchers often need extra filtering for sensitive analog circuits.' },

      { type: 'multiple_choice', difficulty: 1, question: 'A switching regulator is more efficient because it...', options: ['Switches fully on/off instead of burning off the excess', 'Uses a considerably bigger heatsink than a linear one does', 'Only ever runs at a very low output current level', 'Converts the wasted energy harmlessly into light'], correct: 0, explanation: 'A fully-on or fully-off switch wastes little power, unlike a linear regulator.' },
      { type: 'fill_blank', difficulty: 1, prompt: 'A buck converter steps the voltage ___ (a boost steps it up).', blank: '___', answer: 'down', hint: 'It is the opposite direction to what a boost converter does.' },
      { type: 'true_false', difficulty: 1, statement: 'A boost converter can produce an output higher than its input, something a linear regulator can never do.', correct: true, explanation: 'A boost steps the voltage up; a linear regulator can only drop it.' },

      { type: 'true_false', difficulty: 2, statement: 'The main downside of a switching regulator versus a linear one is more complexity and switching noise.', correct: true, explanation: 'Switchers are efficient but noisier and more complex than a simple linear.' },
      { type: 'multiple_choice', difficulty: 1, question: 'Tap the IC chip a switching regulator is built around.', options: ['IC chip', 'Electrolytic capacitor', 'Resistor', 'Diode'], optionImages: ['/components/ic-dip.png', '/components/capacitor-electrolytic.png', '/components/resistor.png', '/components/diode.png'], correct: 0, explanation: 'A switching regulator centres on a controller IC plus an inductor, diode, and capacitors.' },
      { type: 'true_false', difficulty: 2, statement: 'For 5V at 2A from 12V with minimal heat, a buck (switching) converter beats a linear regulator.', correct: true, explanation: 'A linear would burn (12−5)×2 = 14W; a buck handles it efficiently and cool.' },

      { type: 'predict_reading', difficulty: 3, question: 'A 90%-efficient buck makes 5V at 2A (10W out) from 12V. The input current is roughly...', options: ['≈ 0.93 A', '≈ 2 A', '≈ 0.42 A', '≈ 5 A'], correct: 0, explanation: 'Pin = Pout/eff = 10/0.9 ≈ 11.1W; Iin = 11.1/12 ≈ 0.93A. A linear would draw the full 2A in.' },
      { type: 'multiple_choice', difficulty: 3, question: 'To run a 5V circuit from a single 3.7V lithium cell, you need a...', options: ['Boost converter (steps 3.7V up to 5V)', 'Buck converter (steps it down)', 'Linear 7805 regulator', 'Simple zener reference'], correct: 0, explanation: '3.7V is below 5V, so you must step up: a boost converter.' },
      { type: 'match', difficulty: 2, instruction: 'Match each converter to what it does to the voltage.', pairs: [['Buck', 'Steps down'], ['Boost', 'Steps up'], ['Buck-boost', 'Either way'], ['Linear', 'Drops down only (as heat)']] },
      { type: 'drag_order', difficulty: 2, instruction: 'Order these supplies from least efficient to most.', items: ['Linear, big drop', 'Linear, small drop', 'Switcher, average', 'Switcher, 95% efficient'], correctOrder: [0, 1, 2, 3] },
    ],
  },

